import { NextResponse } from "next/server";




export async function POST(req) {
    

    try{

        const data = await req.json();

        console.log(data);
        


        return NextResponse.json({
            data : data,
            message : "data is updated"
        })



    }catch(err){

        return NextResponse.json({
          err: err,
          message: "data is not updated",
        });
    }

}